patch:
--- a/counter.v
+++ b/counter.v
@@ -1,14 +1,14 @@
 module counter_16bit(
   input wire clk,
   input wire reset,
   input wire enable,
   output wire [15:0] count_out
 );
   reg [15:0] counter;
   always @(posedge clk or posedge reset)
     if (reset) counter <= 16'b0;
     else if (enable) counter <= counter + 1;
   assign count_out = counter;
 endmodule

 module system;
   wire clk, rst, en;
-  wire [15:0] cnt;
-  counter_16bit c1 (.clk(clk), .rst(rst), .en(en));
+  wire [15:0] cnt;
+  counter_16bit c1 (.clk(clk), .reset(rst), .enable(en), .count_out(cnt));
 endmodule

